+package com.minio.fileservice.config;
+
+import com.minio.fileservice.enums.FileCategory;
+import lombok.Data;
+import org.springframework.boot.context.properties.ConfigurationProperties;
+import org.springframework.stereotype.Component;
+
+import java.util.Map;
+
+/**
+ * 文件校验规则配置
+ * 对应 application.yml: file.rules.*
+ */
+@Data
+@Component
+@ConfigurationProperties(prefix = "file")
+public class FileRuleProperties {
+
+    /** key: video/audio/image/document/default */
+    private Map<String, CategoryRule> rules;
+
+    @Data
+    public static class CategoryRule {
+        /** 最大字节数 */
+        private long maxSizeBytes;
+        /** 允许的扩展名（逗号分隔），为空则不限制 */
+        private String allowedExtensions;
+        /** 目标 Bucket */
+        private String bucket;
+    }
+
+    /**
+     * 根据分类枚举获取对应规则
+     */
+    public CategoryRule getRuleFor(FileCategory category) {
+        if (rules == null) return null;
+        CategoryRule rule = rules.get(category.getCode());
+        if (rule != null) return rule;
+        return rules.get("default");
+    }
+
+    /**
+     * 根据分类获取目标 Bucket
+     */
+    public String getBucketFor(FileCategory category) {
+        CategoryRule rule = getRuleFor(category);
+        if (rule != null && rule.getBucket() != null) return rule.getBucket();
+        return category.getBucket();
+    }
+}

