+package com.minio.fileservice.config;
+
+import io.minio.MinioClient;
+import lombok.Data;
+import org.springframework.boot.context.properties.ConfigurationProperties;
+import org.springframework.context.annotation.Bean;
+import org.springframework.context.annotation.Configuration;
+
+/**
+ * MinIO 客户端配置
+ * 对应 application.yml: minio.*
+ */
+@Data
+@Configuration
+@ConfigurationProperties(prefix = "minio")
+public class MinioConfig {
+
+    private String endpoint;
+    private String accessKey;
+    private String secretKey;
+    private String region = "us-east-1";
+
+    @Bean
+    public MinioClient minioClient() {
+        return MinioClient.builder()
+                .endpoint(endpoint)
+                .credentials(accessKey, secretKey)
+                .region(region)
+                .build();
+    }
+}

Index: file-service/src/main/java/com/minio/fileservice/controller/FileRecordController.java
===================================================================
--- file-service/src/main/java/com/minio/fileservice/controller/FileRecordController.java	
+++ file-service/src/main/java/com/minio/fileservice/controller/FileRecordController.java	
@@ -0,0 +1,146 @@
+package com.minio.fileservice.controller;
+
+import com.minio.fileservice.dto.ApiResponse;
+import com.minio.fileservice.dto.FileRecordListItem;
+import com.minio.fileservice.entity.FileUploadRecord;
+import com.minio.fileservice.enums.UploadStatus;
+import com.minio.fileservice.repository.FileUploadRecordRepository;
+import jakarta.servlet.http.HttpServletRequest;
+import lombok.RequiredArgsConstructor;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.http.ResponseEntity;
+import org.springframework.web.bind.annotation.*;
+
+import java.util.List;
+import java.util.Map;
+import java.util.stream.Collectors;
+
+/**
+ * 上传记录查询 Controller
+ * 专供前端"查看上传记录"页使用
+ *
+ * API:
+ *   GET /api/v1/records              查询当前用户的上传记录
+ *   GET /api/v1/records?status=PAUSED 按状态过滤
+ *   GET /api/v1/records?all=true     查询全部用户（管理用途）
+ *   GET /api/v1/records/stats        状态汇总统计
+ */
+@Slf4j
+@RestController
+@RequestMapping("/api/v1/records")
+@RequiredArgsConstructor
+@CrossOrigin(origins = "*", allowedHeaders = "*")
+public class FileRecordController {
+
+    private final FileUploadRecordRepository repository;
+
+    /**
+     * 列出上传记录
+     * @param status 可选，按状态过滤 (PENDING/UPLOADING/PAUSED/SUCCESS/FAILED/CANCELLED)
+     * @param all    可选，true=查询全部用户，false/空=仅当前用户
+     */
+    @GetMapping
+    public ResponseEntity<ApiResponse<List<FileRecordListItem>>> list(
+            @RequestParam(required = false) String status,
+            @RequestParam(required = false, defaultValue = "false") boolean all,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+
+        List<FileUploadRecord> records;
+        UploadStatus statusEnum = parseStatus(status);
+
+        if (all) {
+            records = (statusEnum != null)
+                    ? repository.findAllByUploadStatusOrderByCreatedAtDesc(statusEnum)
+                    : repository.findAllByOrderByCreatedAtDesc();
+        } else {
+            records = (statusEnum != null)
+                    ? repository.findByUsernameAndUploadStatusOrderByCreatedAtDesc(username, statusEnum)
+                    : repository.findByUsernameOrderByCreatedAtDesc(username);
+        }
+
+        List<FileRecordListItem> items = records.stream()
+                .map(FileRecordListItem::from)
+                .collect(Collectors.toList());
+
+        return ResponseEntity.ok(ApiResponse.ok(items));
+    }
+
+    /**
+     * 状态汇总统计（用于查看页顶部卡片展示）
+     */
+    @GetMapping("/stats")
+    public ResponseEntity<ApiResponse<Map<String, Long>>> stats(
+            @RequestParam(required = false, defaultValue = "false") boolean all,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        List<FileUploadRecord> records = all
+                ? repository.findAllByOrderByCreatedAtDesc()
+                : repository.findByUsernameOrderByCreatedAtDesc(username);
+
+        Map<String, Long> counts = records.stream()
+                .filter(r -> r.getUploadStatus() != null)
+                .collect(Collectors.groupingBy(
+                        r -> r.getUploadStatus().name(),
+                        Collectors.counting()));
+
+        // 补齐缺失状态（前端展示卡片需要）
+        for (UploadStatus s : UploadStatus.values()) {
+            counts.putIfAbsent(s.name(), 0L);
+        }
+        counts.put("TOTAL", (long) records.size());
+
+        return ResponseEntity.ok(ApiResponse.ok(counts));
+    }
+
+    /** 查询单条详情 */
+    @GetMapping("/{fileId}")
+    public ResponseEntity<ApiResponse<FileRecordListItem>> detail(
+            @PathVariable String fileId,
+            HttpServletRequest httpRequest) {
+
+        return repository.findByFileId(fileId)
+                .map(r -> ResponseEntity.ok(ApiResponse.ok(FileRecordListItem.from(r))))
+                .orElseGet(() -> ResponseEntity.status(404)
+                        .body(ApiResponse.fail("记录不存在: " + fileId)));
+    }
+
+    /** 删除记录（仅删表行，不删 MinIO 对象） */
+    @DeleteMapping("/{fileId}")
+    public ResponseEntity<ApiResponse<Void>> delete(
+            @PathVariable String fileId,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        FileUploadRecord r = repository.findByFileId(fileId).orElse(null);
+        if (r == null) {
+            return ResponseEntity.status(404).body(ApiResponse.fail("记录不存在"));
+        }
+        if (!r.getUsername().equals(username)) {
+            return ResponseEntity.status(403).body(ApiResponse.fail("无权删除他人的记录"));
+        }
+        repository.delete(r);
+        return ResponseEntity.ok(ApiResponse.ok("已删除", null));
+    }
+
+    // ── 辅助 ────────────────────────────────────────────────────
+
+    private UploadStatus parseStatus(String s) {
+        if (s == null || s.isBlank()) return null;
+        try {
+            return UploadStatus.valueOf(s.toUpperCase());
+        } catch (IllegalArgumentException e) {
+            return null;
+        }
+    }
+
+    private String getUsername(HttpServletRequest req) {
+        String username = req.getHeader("X-Username");
+        if (username == null || username.isBlank()) {
+            username = "anonymous";
+        }
+        return username;
+    }
+}

