@@ -0,0 +1,152 @@
+package com.minio.fileservice.controller;
+
+import com.minio.fileservice.dto.*;
+import com.minio.fileservice.service.FileUploadService;
+import jakarta.servlet.http.HttpServletRequest;
+import lombok.RequiredArgsConstructor;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.http.ResponseEntity;
+import org.springframework.web.bind.annotation.*;
+import org.springframework.web.multipart.MultipartFile;
+
+/**
+ * 文件上传 REST API 控制器
+ *
+ * 完整上传流程（前端与后端协作）：
+ *   1. POST /api/v1/upload/init   → 预检 + 创建会话，返回策略
+ *   2. POST /api/v1/upload/file   → 上传文件流（直接/普通/分片/流式）
+ *   3. GET  /api/v1/upload/progress/{fileId} → 轮询进度
+ *
+ * 断点续传：
+ *   4. POST /api/v1/upload/pause/{fileId}   → 暂停
+ *   5. POST /api/v1/upload/resume/{fileId}  → 恢复
+ *   6. POST /api/v1/upload/retry/{fileId}   → 重试失败任务
+ */
+@Slf4j
+@RestController
+@RequestMapping("/api/v1/upload")
+@RequiredArgsConstructor
+@CrossOrigin(origins = "*", allowedHeaders = "*")
+public class FileUploadController {
+
+    private final FileUploadService uploadService;
+
+    // ── 1. 预检初始化 ───────────────────────────────────────────
+
+    /**
+     * 上传预检：校验文件 + 决定策略
+     * 前端在发送文件数据前必须先调用此接口
+     *
+     * 请求体: { "fileId": "uuid", "fileName": "a.mp4", "fileSize": 1024000, "mimeType": "video/mp4" }
+     * 响应:
+     *   - validationError 非空 → 文件不合规，前端展示错误
+     *   - strategy → 前端按此策略选择上传方式
+     */
+    @PostMapping("/init")
+    public ResponseEntity<ApiResponse<UploadInitResponse>> initUpload(
+            @RequestBody UploadInitRequest request,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        log.info("[INIT] 用户={}, 文件={}, 大小={}", username, request.getFileName(), request.getFileSize());
+
+        UploadInitResponse resp = uploadService.initUpload(request, username);
+
+        if (resp.getValidationError() != null) {
+            log.warn("[INIT] 校验失败: {}", resp.getValidationError());
+            return ResponseEntity.ok(ApiResponse.fail(resp.getValidationError()));
+        }
+
+        return ResponseEntity.ok(ApiResponse.ok(resp));
+    }
+
+    // ── 2. 上传文件 ─────────────────────────────────────────────
+
+    /**
+     * 上传文件（所有策略共用此接口，后端根据 fileId 查找对应策略执行）
+     * 请求为 multipart/form-data:
+     *   - fileId: 与 /init 时传入的一致
+     *   - file:   文件内容
+     */
+    @PostMapping("/file")
+    public ResponseEntity<ApiResponse<Void>> uploadFile(
+            @RequestParam("fileId") String fileId,
+            @RequestParam("file") MultipartFile file,
+            HttpServletRequest httpRequest) throws Exception {
+
+        String username = getUsername(httpRequest);
+        log.info("[UPLOAD] 用户={}, fileId={}, 文件={}, 大小={}",
+                username, fileId, file.getOriginalFilename(), file.getSize());
+
+        uploadService.doUpload(fileId, file.getInputStream(),
+                file.getContentType(), username);
+
+        return ResponseEntity.ok(ApiResponse.ok("上传任务已提交", null));
+    }
+
+    // ── 3. 进度查询 ─────────────────────────────────────────────
+
+    /**
+     * 查询上传进度（前端轮询）
+     * 响应: { uploadPercent, uploadedBytes, totalBytes, status, url }
+     */
+    @GetMapping("/progress/{fileId}")
+    public ResponseEntity<ApiResponse<UploadProgressResponse>> getProgress(
+            @PathVariable String fileId,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        UploadProgressResponse progress = uploadService.getProgress(fileId, username);
+        return ResponseEntity.ok(ApiResponse.ok(progress));
+    }
+
+    // ── 4. 暂停上传 ─────────────────────────────────────────────
+
+    @PostMapping("/pause/{fileId}")
+    public ResponseEntity<ApiResponse<Void>> pauseUpload(
+            @PathVariable String fileId,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        uploadService.pauseUpload(fileId, username);
+        return ResponseEntity.ok(ApiResponse.ok("上传已暂停", null));
+    }
+
+    // ── 5. 恢复上传 ─────────────────────────────────────────────
+
+    @PostMapping("/resume/{fileId}")
+    public ResponseEntity<ApiResponse<UploadInitResponse>> resumeUpload(
+            @PathVariable String fileId,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        UploadInitResponse resp = uploadService.resumeUpload(fileId, username);
+        return ResponseEntity.ok(ApiResponse.ok("恢复信息已准备", resp));
+    }
+
+    // ── 6. 重试失败 ─────────────────────────────────────────────
+
+    @PostMapping("/retry/{fileId}")
+    public ResponseEntity<ApiResponse<UploadInitResponse>> retryUpload(
+            @PathVariable String fileId,
+            HttpServletRequest httpRequest) {
+
+        String username = getUsername(httpRequest);
+        UploadInitResponse resp = uploadService.retryUpload(fileId, username);
+        return ResponseEntity.ok(ApiResponse.ok("重试已就绪", resp));
+    }
+
+    // ── 辅助 ────────────────────────────────────────────────────
+
+    /**
+     * 从请求头/会话中获取当前用户名
+     * 微服务模式下：由 API 网关 / Flask 在请求头 X-Username 中传入
+     */
+    private String getUsername(HttpServletRequest req) {
+        String username = req.getHeader("X-Username");
+        if (username == null || username.isBlank()) {
+            username = "anonymous";
+        }
+        return username;
+    }
+}

