+package com.minio.fileservice.entity;
+
+import com.minio.fileservice.enums.FileCategory;
+import com.minio.fileservice.enums.NodeType;
+import com.minio.fileservice.enums.UploadStatus;
+import com.minio.fileservice.enums.UploadStrategy;
+import jakarta.persistence.*;
+import lombok.Data;
+import lombok.NoArgsConstructor;
+import org.hibernate.annotations.CreationTimestamp;
+import org.hibernate.annotations.UpdateTimestamp;
+
+import java.math.BigDecimal;
+import java.time.OffsetDateTime;
+
+/**
+ * 文件上传记录实体
+ * 对应数据库表: file_upload_record
+ */
+@Data
+@NoArgsConstructor
+@Entity
+@Table(name = "file_upload_record")
+public class FileUploadRecord {
+
+    @Id
+    @GeneratedValue(strategy = GenerationType.IDENTITY)
+    private Long id;
+
+    /** 前端生成的 UUID，用于断点续传唯一标识 */
+    @Column(name = "file_id", nullable = false, unique = true, length = 64)
+    private String fileId;
+
+    /** 原始文件名 */
+    @Column(name = "file_name", nullable = false, length = 512)
+    private String fileName;
+
+    /** MinIO 存储路径: bucket/key */
+    @Column(name = "storage_path", length = 1024)
+    private String storagePath;
+
+    /** 文件字节数 */
+    @Column(name = "file_size", nullable = false)
+    private Long fileSize = 0L;
+
+    /** 文件分类: video/audio/image/document/unclassified */
+    @Enumerated(EnumType.STRING)
+    @Column(name = "file_type", length = 32)
+    private FileCategory fileType;
+
+    /** MIME 类型 */
+    @Column(name = "mime_type", length = 128)
+    private String mimeType;
+
+    /** 文件扩展名（不含点） */
+    @Column(name = "extension", length = 32)
+    private String extension;
+
+    /** 目标 MinIO Bucket */
+    @Column(name = "bucket", length = 128)
+    private String bucket;
+
+    /** 父节点 ID（支持文件夹层级） */
+    @Column(name = "parent_id")
+    private Long parentId;
+
+    /** 节点类型: FILE / FOLDER */
+    @Enumerated(EnumType.STRING)
+    @Column(name = "node_type", nullable = false, length = 16)
+    private NodeType nodeType = NodeType.FILE;
+
+    /** 上传状态 */
+    @Enumerated(EnumType.STRING)
+    @Column(name = "upload_status", nullable = false, length = 32)
+    private UploadStatus uploadStatus = UploadStatus.PENDING;
+
+    /** 使用的上传策略 */
+    @Enumerated(EnumType.STRING)
+    @Column(name = "upload_strategy", length = 32)
+    private UploadStrategy uploadStrategy;
+
+    /** 失败原因 */
+    @Column(name = "error_message", columnDefinition = "TEXT")
+    private String errorMessage;
+
+    /** MinIO Multipart Upload ID（分片上传时使用） */
+    @Column(name = "upload_id", length = 256)
+    private String uploadId;
+
+    /** 总分片数 */
+    @Column(name = "total_chunks")
+    private Integer totalChunks = 0;
+
+    /** 已上传分片数 */
+    @Column(name = "uploaded_chunks")
+    private Integer uploadedChunks = 0;
+
+    /** 每片大小（字节） */
+    @Column(name = "chunk_size")
+    private Long chunkSize = 0L;
+
+    /** 已上传字节数 */
+    @Column(name = "uploaded_bytes")
+    private Long uploadedBytes = 0L;
+
+    /**
+     * 上传百分比 = 已上传字节数 / 总字节数 * 100
+     * 精度: 5位，小数2位（如 99.99）
+     */
+    @Column(name = "upload_percent", precision = 5, scale = 2)
+    private BigDecimal uploadPercent = BigDecimal.ZERO;
+
+    /** 上传用户 */
+    @Column(name = "username", nullable = false, length = 128)
+    private String username;
+
+    /** MinIO 访问 URL */
+    @Column(name = "url", length = 1024)
+    private String url;
+
+    @CreationTimestamp
+    @Column(name = "created_at", updatable = false)
+    private OffsetDateTime createdAt;
+
+    @UpdateTimestamp
+    @Column(name = "updated_at")
+    private OffsetDateTime updatedAt;
+
+    // ── 便捷方法 ──────────────────────────────────────────────
+
+    /** 更新进度百分比（自动计算） */
+    public void refreshPercent() {
+        if (fileSize != null && fileSize > 0 && uploadedBytes != null) {
+            double pct = (double) uploadedBytes / fileSize * 100;
+            this.uploadPercent = BigDecimal.valueOf(Math.min(pct, 100.0))
+                    .setScale(2, java.math.RoundingMode.HALF_UP);
+        }
+    }
+}

