+package com.minio.fileservice.exception;
+
+import com.minio.fileservice.dto.ApiResponse;
+import lombok.extern.slf4j.Slf4j;
+import org.springframework.http.HttpStatus;
+import org.springframework.http.ResponseEntity;
+import org.springframework.web.bind.annotation.ExceptionHandler;
+import org.springframework.web.bind.annotation.RestControllerAdvice;
+import org.springframework.web.multipart.MaxUploadSizeExceededException;
+
+/**
+ * 全局异常处理器
+ * 确保所有异常都返回结构化 JSON，不暴露后台堆栈到前端
+ */
+@Slf4j
+@RestControllerAdvice
+public class GlobalExceptionHandler {
+
+    /** 文件校验失败 → 400 + 友好提示 */
+    @ExceptionHandler(FileValidationException.class)
+    public ResponseEntity<ApiResponse<Void>> handleValidation(FileValidationException e) {
+        log.warn("[VALIDATION] 文件 {} 校验失败({}): {}", e.getFileName(), e.getRule(), e.getMessage());
+        return ResponseEntity.badRequest()
+                .body(ApiResponse.fail(e.getMessage()));
+    }
+
+    /** 上传业务异常 → 400 */
+    @ExceptionHandler(UploadException.class)
+    public ResponseEntity<ApiResponse<Void>> handleUpload(UploadException e) {
+        log.warn("[UPLOAD] 业务异常: {}", e.getMessage());
+        return ResponseEntity.badRequest()
+                .body(ApiResponse.fail(e.getMessage()));
+    }
+
+    /** 文件超过 Spring multipart 大小限制 → 413 */
+    @ExceptionHandler(MaxUploadSizeExceededException.class)
+    public ResponseEntity<ApiResponse<Void>> handleMaxSize(MaxUploadSizeExceededException e) {
+        log.warn("[UPLOAD] 文件超过最大上传限制");
+        return ResponseEntity.status(HttpStatus.PAYLOAD_TOO_LARGE)
+                .body(ApiResponse.fail("文件超过系统最大上传限制 (10GB)"));
+    }
+
+    /** 未预期异常 → 500，不暴露细节 */
+    @ExceptionHandler(Exception.class)
+    public ResponseEntity<ApiResponse<Void>> handleGeneral(Exception e) {
+        log.error("[SYSTEM] 未处理异常", e);
+        return ResponseEntity.internalServerError()
+                .body(ApiResponse.fail("服务内部错误，请联系管理员"));
+    }
+}

