+<!DOCTYPE html>
+<html lang="zh-CN">
+<head>
+<meta charset="UTF-8">
+<meta name="viewport" content="width=device-width, initial-scale=1.0">
+<title>上传记录 — MinIO 数据平台</title>
+<link rel="stylesheet" href="/static/style.css">
+<style>
+  .records-app { max-width: 1400px; margin: 0 auto; padding: 16px; }
+
+  /* 顶部工具栏 */
+  .records-toolbar {
+    display: flex; justify-content: space-between; align-items: center;
+    background: var(--panel-bg); padding: 16px 20px; border-radius: var(--radius);
+    box-shadow: var(--shadow); margin-bottom: 16px;
+  }
+  .records-toolbar h1 { font-size: 20px; }
+  .records-toolbar .actions { display: flex; gap: 10px; align-items: center; }
+
+  /* 状态卡片 */
+  .stat-cards {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
+    gap: 12px;
+    margin-bottom: 16px;
+  }
+  .stat-card {
+    background: var(--panel-bg); padding: 14px; border-radius: var(--radius);
+    box-shadow: var(--shadow); cursor: pointer; transition: transform .15s;
+    border: 2px solid transparent;
+  }
+  .stat-card:hover { transform: translateY(-2px); }
+  .stat-card.active { border-color: var(--primary); }
+  .stat-card .label { font-size: 12px; color: var(--text-muted); margin-bottom: 6px; }
+  .stat-card .value { font-size: 24px; font-weight: 600; }
+  .stat-card.TOTAL    .value { color: var(--text); }
+  .stat-card.PENDING  .value { color: #6b7280; }
+  .stat-card.UPLOADING .value { color: var(--primary); }
+  .stat-card.PAUSED   .value { color: #f59e0b; }
+  .stat-card.SUCCESS  .value { color: var(--success); }
+  .stat-card.FAILED   .value { color: var(--danger); }
+  .stat-card.CANCELLED .value { color: #9ca3af; }
+
+  /* 数据源提示 */
+  .source-badge {
+    display: inline-block; padding: 2px 10px; border-radius: 12px;
+    font-size: 12px; font-weight: 500;
+  }
+  .source-badge.pg    { background: #dbeafe; color: #1e40af; }
+  .source-badge.local { background: #fef3c7; color: #92400e; }
+
+  /* 表格 */
+  .records-table-wrap {
+    background: var(--panel-bg); border-radius: var(--radius); box-shadow: var(--shadow);
+    overflow: hidden;
+  }
+  .records-table { width: 100%; border-collapse: collapse; font-size: 13px; }
+  .records-table th, .records-table td {
+    padding: 10px 12px; border-bottom: 1px solid var(--border); text-align: left;
+    white-space: nowrap;
+  }
+  .records-table th {
+    background: #f9fafb; font-weight: 600; color: var(--text-muted);
+    font-size: 12px; text-transform: uppercase; letter-spacing: .03em;
+  }
+  .records-table td.filename { max-width: 280px; overflow: hidden; text-overflow: ellipsis; }
+  .records-table tr:hover { background: #f9fafb; }
+
+  /* 进度条 */
+  .pct-bar { width: 120px; height: 8px; background: #e5e7eb; border-radius: 4px; overflow: hidden; }
+  .pct-fill { height: 100%; background: var(--primary); transition: width .3s; }
+  .pct-fill.SUCCESS { background: var(--success); }
+  .pct-fill.FAILED  { background: var(--danger); }
+  .pct-fill.PAUSED  { background: #f59e0b; }
+  .pct-text { font-size: 11px; color: var(--text-muted); margin-top: 2px; }
+
+  /* 状态徽章 */
+  .status-badge {
+    display: inline-block; padding: 2px 10px; border-radius: 10px;
+    font-size: 11px; font-weight: 500;
+  }
+  .status-badge.PENDING   { background: #f3f4f6; color: #6b7280; }
+  .status-badge.UPLOADING { background: #dbeafe; color: #1e40af; }
+  .status-badge.PAUSED    { background: #fef3c7; color: #92400e; }
+  .status-badge.SUCCESS   { background: #d1fae5; color: #065f46; }
+  .status-badge.FAILED    { background: #fee2e2; color: #991b1b; }
+  .status-badge.CANCELLED { background: #e5e7eb; color: #6b7280; }
+
+  /* 空状态 */
+  .empty-state {
+    padding: 60px 20px; text-align: center; color: var(--text-muted);
+  }
+  .empty-state .icon { font-size: 48px; margin-bottom: 12px; }
+
+  /* 加载状态 */
+  .loading { padding: 40px; text-align: center; color: var(--text-muted); }
+</style>
+</head>
+<body>
+
+<div class="records-app">
+
+  <!-- 顶部工具栏 -->
+  <div class="records-toolbar">
+    <h1>📊 上传记录</h1>
+    <div class="actions">
+      <span id="sourceBadge"></span>
+      <button class="btn btn-small" onclick="loadRecords()">🔄 刷新</button>
+      <button class="btn btn-small btn-primary" onclick="window.location.href='/'">返回上传</button>
+    </div>
+  </div>
+
+  <!-- 状态统计卡片（点击过滤） -->
+  <div class="stat-cards" id="statCards"></div>
+
+  <!-- 表格 -->
+  <div class="records-table-wrap">
+    <table class="records-table" id="recordsTable">
+      <thead>
+        <tr>
+          <th>文件ID</th>
+          <th>文件名</th>
+          <th>存储路径</th>
+          <th>大小</th>
+          <th>上级</th>
+          <th>类型</th>
+          <th>状态</th>
+          <th>分片(已传/总数)</th>
+          <th>创建时间</th>
+          <th>更新时间</th>
+          <th>操作</th>
+        </tr>
+      </thead>
+      <tbody id="recordsTbody">
+        <tr><td colspan="11" class="loading">加载中...</td></tr>
+      </tbody>
+    </table>
+  </div>
+</div>
+
+<script>
+let currentFilter = ""; // 当前状态过滤
+let lastRecords = [];
+
+const STATUS_LABEL = {
+  TOTAL:     "全部",
+  PENDING:   "待上传",
+  UPLOADING: "上传中",
+  PAUSED:    "已暂停",
+  SUCCESS:   "成功",
+  FAILED:    "失败",
+  CANCELLED: "已取消",
+};
+
+const STRATEGY_LABEL = {
+  DIRECT:        "直接上传",
+  SIMPLE:        "普通上传",
+  SIMPLE_LARGE:  "普通上传",
+  MULTIPART:     "分片上传",
+  RESUMABLE:     "分片+断点续传",
+  STREAMING:     "流式+多线程",
+};
+
+function isShowAll() {
+  // username 字段已移除，统一显示所有记录
+  return true;
+}
+
+async function loadRecords() {
+  const tbody = document.getElementById("recordsTbody");
+  tbody.innerHTML = '<tr><td colspan="11" class="loading">加载中...</td></tr>';
+
+  // 先加载统计卡片
+  loadStats();
+
+  // 再加载列表
+  try {
+    const params = new URLSearchParams();
+    if (currentFilter) params.set("status", currentFilter);
+    const r = await fetch("/api/records?" + params.toString());
+    if (r.status === 401) { window.location.href = "/login"; return; }
+    const data = await r.json();
+
+    // 数据源徽章
+    const badge = document.getElementById("sourceBadge");
+    if (data.source === "pg") {
+      badge.innerHTML = '<span class="source-badge pg">🟢 PostgreSQL</span>';
+    } else {
+      badge.innerHTML = '<span class="source-badge local">🟡 本地 SQLite</span>';
+    }
+
+    lastRecords = data.records || [];
+    renderTable(lastRecords);
+  } catch (e) {
+    tbody.innerHTML = `<tr><td colspan="12" class="empty-state">加载失败: ${e.message}</td></tr>`;
+  }
+}
+
+async function loadStats() {
+  try {
+    const params = new URLSearchParams();
+    if (isShowAll()) params.set("all", "true");
+    const r = await fetch("/api/records/stats?" + params.toString());
+    const data = await r.json();
+    const stats = data.stats || {};
+    renderStats(stats);
+  } catch (e) {
+    console.error("统计加载失败", e);
+  }
+}
+
+function renderStats(stats) {
+  const order = ["TOTAL", "PENDING", "UPLOADING", "PAUSED", "SUCCESS", "FAILED", "CANCELLED"];
+  const html = order.map(k => {
+    const count = stats[k] || 0;
+    const filter = k === "TOTAL" ? "" : k;
+    const active = (filter === currentFilter) ? "active" : "";
+    return `
+      <div class="stat-card ${k} ${active}" onclick="filterByStatus('${filter}')">
+        <div class="label">${STATUS_LABEL[k]}</div>
+        <div class="value">${count}</div>
+      </div>`;
+  }).join("");
+  document.getElementById("statCards").innerHTML = html;
+}
+
+function filterByStatus(status) {
+  currentFilter = status;
+  loadRecords();
+}
+
+function renderTable(records) {
+  const tbody = document.getElementById("recordsTbody");
+  if (records.length === 0) {
+    tbody.innerHTML = `
+      <tr><td colspan="11">
+        <div class="empty-state">
+          <div class="icon">📭</div>
+          <div>暂无上传记录</div>
+        </div>
+      </td></tr>`;
+    return;
+  }
+
+  tbody.innerHTML = records.map(r => {
+    const status = r.uploadStatus || "PENDING";
+    const chunks = (r.totalChunks > 0)
+      ? `${r.uploadedChunks || 0} / ${r.totalChunks}`
+      : "-";
+
+    // 文件 ID 只展示前 8 位（hover 看完整）
+    const shortId = (r.fileId || "").substring(0, 8);
+
+    // 删除按钮：fileId 是 UUID 不会有引号，文件名通过 data 属性传递避免转义问题
+    const delBtn = `<button class="btn btn-small btn-danger" data-file-id="${r.fileId}" onclick="deleteRecord(this.dataset.fileId)">删除</button>`;
+
+    return `
+      <tr>
+        <td title="${r.fileId || ''}"><code>${shortId}</code></td>
+        <td class="filename" title="${r.fileName || ''}">${r.fileName || '-'}</td>
+        <td class="filename" title="${r.storagePath || ''}">${r.storagePath || '-'}</td>
+        <td>${r.fileSizeDisplay || '-'}</td>
+        <td>${r.parentId || '-'}</td>
+        <td>${r.nodeType || 'FILE'}</td>
+        <td><span class="status-badge ${status}">${STATUS_LABEL[status] || status}</span></td>
+        <td>${chunks}</td>
+        <td>${r.createdAt || '-'}</td>
+        <td>${r.updatedAt || '-'}</td>
+        <td>${delBtn}</td>
+      </tr>`;
+  }).join("");
+}
+
+async function deleteRecord(fileId) {
+  // 从当前数据中找文件名展示给用户
+  const record = (lastRecords || []).find(r => r.fileId === fileId);
+  const fileName = record ? record.fileName : fileId;
+  if (!confirm(`确定删除记录 "${fileName}" 吗？\n（同时会清理 MinIO 上的临时分片文件）`)) return;
+  try {
+    const r = await fetch(`/api/records/${fileId}`, { method: "DELETE" });
+    const data = await r.json();
+    if (data.status === "ok") {
+      loadRecords();
+    } else {
+      alert("删除失败: " + (data.error || "未知错误"));
+    }
+  } catch (e) {
+    alert("删除失败: " + e.message);
+  }
+}
+
+function formatBytes(b) {
+  if (b == null || b < 0) return "未知";
+  if (b < 1024 * 1024) return (Math.max(b / 1024, 1)).toFixed(0) + " KB";
+  if (b < 1024 * 1024 * 1024) return (b / (1024 * 1024)).toFixed(1) + " MB";
+  return (b / (1024 * 1024 * 1024)).toFixed(2) + " GB";
+}
+
+// 初始加载
+document.addEventListener("DOMContentLoaded", loadRecords);
+</script>
+
+</body>
+</html>
